insert into public.modelos
  (id, titulo, categoria, blocks, variables, is_favorite, is_modelo_sistema)
values
  ('a50c4fa7-a906-4fb9-ae88-3a58329f38f2', 'Contrato de Prestação de Serviços', 'contratos', '[{"id":"d6469888-edb6-4081-a558-7fbc6f3ed807","type":"heading","text":"CONTRATO DE PRESTAÇÃO DE SERVIÇOS ADVOCATÍCIOS","align":"center","bold":true},{"id":"4ff7a659-7c5c-48d2-a71e-ffb0e11e207c","type":"paragraph","text":"Pelo presente instrumento particular, de um lado {{NOME_ESCRITORIO}}, doravante denominado CONTRATADO, e de outro lado {{NOME_CLIENTE}}, portador(a) do CPF/CNPJ nº {{CPF_CLIENTE}}, doravante denominado(a) CONTRATANTE, têm entre si justo e contratado o presente instrumento, mediante as cláusulas seguintes."},{"id":"59998c36-14df-4faa-a856-14b6369c9f95","type":"clause","text":"CLÁUSULA 1ª — DO OBJETO","bold":true},{"id":"ee3b51cc-13a8-403c-a972-89a3e5a1be7e","type":"paragraph","text":"O presente contrato tem por objeto: {{OBJETO_CONTRATO}}."},{"id":"efc9e8bd-ae64-466d-bbb2-07985b7db845","type":"clause","text":"CLÁUSULA 2ª — DOS HONORÁRIOS","bold":true},{"id":"b7db0614-21ab-4eb3-a50c-545e8ce55bc6","type":"paragraph","text":"Pelos serviços prestados, o CONTRATANTE pagará ao CONTRATADO o valor de {{VALOR}}, nas condições acordadas entre as partes."},{"id":"68d32c5d-badc-4cb5-a7ce-4256f061047a","type":"clause","text":"CLÁUSULA 3ª — DO PRAZO","bold":true},{"id":"45062fbf-a5cf-4aa3-89da-d55fe3c2b87c","type":"paragraph","text":"O presente contrato vigorará pelo prazo de {{PRAZO}}, podendo ser renovado mediante acordo entre as partes."},{"id":"664ce9e2-f35d-4e51-9ddb-530cbd5167c7","type":"clause","text":"CLÁUSULA 4ª — DO FORO","bold":true},{"id":"e2178553-10ff-4404-a411-a3fff6413184","type":"paragraph","text":"Fica eleito o foro de {{FORO}} para dirimir quaisquer dúvidas oriundas do presente contrato."},{"id":"014b16ac-16e5-48f5-b5a8-34372b8cd3ea","type":"paragraph","text":"E por estarem justos e contratados, firmam o presente instrumento em duas vias de igual teor."},{"id":"a22b3dd0-536a-4069-b3d1-cedb8aa67a24","type":"paragraph","text":"{{DATA}}","align":"right"},{"id":"4d6dabe1-8e9f-40b1-824b-95e8c7d9bef7","type":"signatureLine","imageRef":"signature"},{"id":"4a9150eb-7ab8-4419-b688-3c55da753672","type":"paragraph","text":"{{NOME_ESCRITORIO}}","align":"center"},{"id":"3e2b2961-fd44-4330-8409-a8e1046efb3e","type":"signatureLine"},{"id":"128ec246-c376-48c0-8e09-6abd7f38b86c","type":"paragraph","text":"{{NOME_CLIENTE}}","align":"center"}]'::jsonb, '[{"token":"NOME_CLIENTE","label":"Nome do cliente","type":"text","required":true,"group":"partes"},{"token":"CPF_CLIENTE","label":"CPF/CNPJ do cliente","type":"cpf","required":true,"group":"partes"},{"token":"NOME_ESCRITORIO","label":"Nome do escritório","type":"text","required":true,"group":"outros"},{"token":"DATA","label":"Data do documento","type":"date","required":true,"group":"valores"},{"token":"OBJETO_CONTRATO","label":"Objeto do contrato","type":"text","required":true,"group":"informacoes"},{"token":"VALOR","label":"Valor do serviço","type":"currency","required":true,"group":"valores"},{"token":"PRAZO","label":"Prazo de vigência","type":"text","required":false,"group":"informacoes"},{"token":"FORO","label":"Foro de eleição","type":"text","required":false,"group":"outros"}]'::jsonb, true, true),
  ('19b5788d-9a8e-42f5-8a86-4e65355c6b9f', 'Procuração Ad Judicia', 'procuracoes', '[{"id":"14da27a0-7d2a-4d45-88e5-5d970178a3e3","type":"heading","text":"PROCURAÇÃO AD JUDICIA ET EXTRA","align":"center","bold":true},{"id":"f16bd4c8-92a0-4bfc-8908-9b6c482b4f0f","type":"paragraph","text":"OUTORGANTE: {{NOME_CLIENTE}}, portador(a) do CPF/CNPJ nº {{CPF_CLIENTE}}, pelo presente instrumento de mandato, nomeia e constitui seu(sua) bastante procurador(a):"},{"id":"91754be0-a304-4e1d-ad98-21dd9b9cee0d","type":"paragraph","text":"OUTORGADO(A): {{NOME_ADVOGADO}}, inscrito(a) na OAB sob o nº {{OAB}}, integrante de {{NOME_ESCRITORIO}}."},{"id":"8b23af58-b929-492f-9dc0-f5bea78afc4d","type":"clause","text":"PODERES","bold":true},{"id":"b8ae320e-94e2-4115-9b14-b07f1ac023a0","type":"paragraph","text":"Confere-lhe amplos poderes para o foro em geral, com a cláusula ad judicia et extra, em qualquer Juízo, Instância ou Tribunal, podendo propor contra quem de direito as ações competentes e defendê-lo(a) nas contrárias, seguindo umas e outras até final decisão, {{PODERES}}."},{"id":"25f83aa0-1fc2-410c-9b49-a99d06f7de88","type":"paragraph","text":"{{DATA}}","align":"right"},{"id":"fecdad69-8854-4bda-8ccb-cb2403712958","type":"signatureLine"},{"id":"a9b5b03c-6bad-40e4-8999-d1645292bf92","type":"paragraph","text":"{{NOME_CLIENTE}}","align":"center"}]'::jsonb, '[{"token":"NOME_CLIENTE","label":"Nome do cliente","type":"text","required":true,"group":"partes"},{"token":"CPF_CLIENTE","label":"CPF/CNPJ do cliente","type":"cpf","required":true,"group":"partes"},{"token":"NOME_ESCRITORIO","label":"Nome do escritório","type":"text","required":true,"group":"outros"},{"token":"DATA","label":"Data do documento","type":"date","required":true,"group":"valores"},{"token":"NOME_ADVOGADO","label":"Nome do advogado","type":"text","required":true,"group":"partes"},{"token":"OAB","label":"Número da OAB","type":"text","required":true,"group":"partes"},{"token":"PODERES","label":"Poderes outorgados","type":"text","required":false,"group":"informacoes"}]'::jsonb, true, true),
  ('91b6fad2-52c0-49a5-ba67-188f8f5c8f76', 'Notificação Extrajudicial', 'notificacoes', '[{"id":"44fbad3a-f2e7-4d48-aaed-b9a2a68a8cbb","type":"heading","text":"NOTIFICAÇÃO EXTRAJUDICIAL","align":"center","bold":true},{"id":"d6b86934-c184-4bfe-92c4-d46f64ed187c","type":"paragraph","text":"Ao(À) Sr(a). {{NOME_NOTIFICADO}}."},{"id":"d1827329-6299-4c83-a55d-bc4b6dff1c6d","type":"paragraph","text":"{{NOME_CLIENTE}}, portador(a) do CPF/CNPJ nº {{CPF_CLIENTE}}, por intermédio de {{NOME_ESCRITORIO}}, vem, respeitosamente, NOTIFICAR Vossa Senhoria acerca do seguinte:"},{"id":"0dba5d1d-de02-453e-afc3-c79e21407ac1","type":"paragraph","text":"{{MOTIVO}}"},{"id":"2ad92b36-7258-40a9-8e76-0090928ee093","type":"paragraph","text":"Fica Vossa Senhoria notificado(a) a se manifestar no prazo de {{PRAZO_RESPOSTA}}, sob pena de serem adotadas as medidas judiciais cabíveis."},{"id":"10704c2a-7514-497e-a60a-feab26fbfce6","type":"paragraph","text":"{{DATA}}","align":"right"},{"id":"d47cae38-264c-4cac-ba25-34be3a0b1dec","type":"signatureLine","imageRef":"signature"},{"id":"a146c268-b030-4b51-820a-1145f4172fb8","type":"paragraph","text":"{{NOME_CLIENTE}}","align":"center"}]'::jsonb, '[{"token":"NOME_CLIENTE","label":"Nome do cliente","type":"text","required":true,"group":"partes"},{"token":"CPF_CLIENTE","label":"CPF/CNPJ do cliente","type":"cpf","required":true,"group":"partes"},{"token":"NOME_ESCRITORIO","label":"Nome do escritório","type":"text","required":true,"group":"outros"},{"token":"DATA","label":"Data do documento","type":"date","required":true,"group":"valores"},{"token":"NOME_NOTIFICADO","label":"Nome do notificado","type":"text","required":true,"group":"partes"},{"token":"MOTIVO","label":"Motivo da notificação","type":"text","required":true,"group":"informacoes"},{"token":"PRAZO_RESPOSTA","label":"Prazo para resposta","type":"text","required":false,"group":"valores"}]'::jsonb, true, true),
  ('0c8291bf-9a3a-4024-8e2a-a5a398e42499', 'Declaração de Hipossuficiência', 'declaracoes', '[{"id":"feb1af79-6e94-4ff7-a349-857716bf3a9c","type":"heading","text":"DECLARAÇÃO DE HIPOSSUFICIÊNCIA ECONÔMICA","align":"center","bold":true},{"id":"9f3b2dbe-a52e-4a84-8967-0f2c1d36c3a2","type":"paragraph","text":"Eu, {{NOME_CLIENTE}}, portador(a) do RG nº {{RG_CLIENTE}} e CPF nº {{CPF_CLIENTE}}, residente e domiciliado(a) em {{ENDERECO_CLIENTE}}, DECLARO, para os devidos fins de direito e sob as penas da lei, não possuir condições financeiras de arcar com as custas processuais e honorários advocatícios sem prejuízo do meu sustento próprio ou de minha família."},{"id":"c2dbd4fe-be53-46d0-bdf9-cb5f3bf64a11","type":"paragraph","text":"Por ser expressão da verdade, firmo a presente declaração."},{"id":"9413c69e-b976-47eb-a1e3-38ac9b55f614","type":"paragraph","text":"{{DATA}}","align":"right"},{"id":"b0770c9a-e149-4d49-98f1-9b65c7b608e2","type":"signatureLine"},{"id":"a2353070-b8d2-4c02-9d6e-96c532b1c38d","type":"paragraph","text":"{{NOME_CLIENTE}}","align":"center"}]'::jsonb, '[{"token":"NOME_CLIENTE","label":"Nome do cliente","type":"text","required":true,"group":"partes"},{"token":"CPF_CLIENTE","label":"CPF/CNPJ do cliente","type":"cpf","required":true,"group":"partes"},{"token":"NOME_ESCRITORIO","label":"Nome do escritório","type":"text","required":true,"group":"outros"},{"token":"DATA","label":"Data do documento","type":"date","required":true,"group":"valores"},{"token":"RG_CLIENTE","label":"RG do cliente","type":"text","required":false,"group":"partes"},{"token":"ENDERECO_CLIENTE","label":"Endereço do cliente","type":"text","required":false,"group":"partes"}]'::jsonb, true, true),
  ('260c8625-aac7-4438-a040-d92d7e29a50d', 'Recibo de Pagamento de Honorários', 'recibos', '[{"id":"86d331f2-a351-40eb-b8da-930befb81bd2","type":"heading","text":"RECIBO DE PAGAMENTO","align":"center","bold":true},{"id":"a1289938-5f71-4a3f-ae25-9b957ecb6b1b","type":"paragraph","text":"Recebi de {{NOME_CLIENTE}}, portador(a) do CPF/CNPJ nº {{CPF_CLIENTE}}, a importância de {{VALOR}}, referente a {{REFERENTE_A}}."},{"id":"70a35d94-0005-431a-b5d7-c9a0c6c5cf9d","type":"paragraph","text":"Para maior clareza, firmo o presente recibo, dando plena e geral quitação."},{"id":"49472b46-52a0-4e76-923f-5dcd70fcf685","type":"paragraph","text":"{{DATA}}","align":"right"},{"id":"aed76255-2021-4e1b-bcb9-bb610237dd53","type":"signatureLine","imageRef":"signature"},{"id":"b1c575c9-f287-4912-9054-37367b2e16d2","type":"paragraph","text":"{{NOME_ESCRITORIO}}","align":"center"}]'::jsonb, '[{"token":"NOME_CLIENTE","label":"Nome do cliente","type":"text","required":true,"group":"partes"},{"token":"CPF_CLIENTE","label":"CPF/CNPJ do cliente","type":"cpf","required":true,"group":"partes"},{"token":"NOME_ESCRITORIO","label":"Nome do escritório","type":"text","required":true,"group":"outros"},{"token":"DATA","label":"Data do documento","type":"date","required":true,"group":"valores"},{"token":"VALOR","label":"Valor recebido","type":"currency","required":true,"group":"valores"},{"token":"REFERENTE_A","label":"Referente a","type":"text","required":true,"group":"informacoes"}]'::jsonb, true, true);
